import { bus } from '../../lib/bus';
import { useStore } from '../../state/store';
import type { Mark } from '../../engine';

function rowFull(cells: ReadonlyArray<Mark>, r: number, w: number): boolean {
  for (let c = 0; c < w; c++) if (cells[r * w + c] === 'unmarked') return false;
  return true;
}

function colFull(cells: ReadonlyArray<Mark>, c: number, w: number, h: number): boolean {
  for (let r = 0; r < h; r++) if (cells[r * w + c] === 'unmarked') return false;
  return true;
}

export function initUnitComplete() {
  let lastBoard = useStore.getState().board;

  useStore.subscribe(s => {
    const next = s.board;
    if (next === lastBoard) return;
    const prev = lastBoard;
    lastBoard = next;

    for (let i = 0; i < next.cells.length; i++) {
      if (next.cells[i] === prev.cells[i]) continue;
      const row = Math.floor(i / next.cols);
      const col = i % next.cols;
      if (!rowFull(prev.cells as ReadonlyArray<Mark>, row, next.cols)
          && rowFull(next.cells as ReadonlyArray<Mark>, row, next.cols)) {
        bus.emit('unitCompleted', { kind: 'row', index: row });
      }
      if (!colFull(prev.cells as ReadonlyArray<Mark>, col, next.cols, next.rows)
          && colFull(next.cells as ReadonlyArray<Mark>, col, next.cols, next.rows)) {
        bus.emit('unitCompleted', { kind: 'col', index: col });
      }
    }
  });
}
