import type { EtchMode, EtchSize } from '../../engine';

export interface ShareTileOpts {
  solution: ReadonlyArray<0|1>;
  rows: number; cols: number;
  size: EtchSize;
  mode: EtchMode;
  date: Date;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  streak: number;
  iso: string;
}

const SIZE_NAMES: Record<EtchSize, string> = {
  sketch: 'Sketch', beginner: 'Beginner',
  intermediate: 'Intermediate', tall: 'Tall', expert: 'Expert',
};

export function buildShareTile(opts: ShareTileOpts): string {
  const day = opts.date.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  const sizeName = SIZE_NAMES[opts.size];
  const min = Math.floor(opts.timeMs / 60_000);
  const sec = Math.floor((opts.timeMs % 60_000) / 1000);
  const time = `${min}:${String(sec).padStart(2, '0')}`;
  const lines: string[] = [`Bilko Etch · ${day} · ${sizeName}`];
  for (let r = 0; r < opts.rows; r++) {
    let line = '';
    for (let c = 0; c < opts.cols; c++) {
      line += opts.solution[r * opts.cols + c] === 1 ? '⬛' : '⬜';
    }
    lines.push(line);
  }
  const m = opts.mistakes;
  const h = opts.hintsUsed;
  lines.push(`⏱ ${time}  ❤️ ${m} mistake${m !== 1 ? 's' : ''}  💡 ${h} hint${h !== 1 ? 's' : ''}`);
  if (opts.mode === 'daily') lines.push(`🔥 streak ${opts.streak}`);
  lines.push(`bilko.run/projects/etch/?d=${opts.iso}`);
  return lines.join('\n');
}
