export type EtchSize = 'sketch' | 'beginner' | 'intermediate' | 'tall' | 'expert';
export type Mark = 'unmarked' | 'fill' | 'cross';
export type CellMarkInput = 'fill' | 'cross' | 'clear';
export type EtchMode = 'daily' | 'free';
export type TechniqueLevel =
  | 'completed-clue'
  | 'overlap'
  | 'forced-edge'
  | 'completed-clue-elim'
  | 'multi-line'
  | 'none';

export interface Coord { row: number; col: number; }
export interface Clues { rows: number[][]; cols: number[][]; }

export interface Board {
  readonly rows: number;
  readonly cols: number;
  readonly clues: Clues;
  /** Row-major. Each entry is a Mark. Frozen array. */
  readonly cells: ReadonlyArray<Mark>;
  /** Original solution (the picture), used for win/mistake check. Read-only. */
  readonly solution: ReadonlyArray<0 | 1>;
}

export const SIZE_DIMS: Record<EtchSize, { w: number; h: number }> = {
  sketch:       { w: 5,  h: 5  },
  beginner:     { w: 10, h: 10 },
  intermediate: { w: 15, h: 15 },
  tall:         { w: 15, h: 20 },
  expert:       { w: 20, h: 20 },
};

export const TARGET_TIMES_MS: Record<EtchSize, number> = {
  sketch:        90_000,
  beginner:      4 * 60_000,
  intermediate: 10 * 60_000,
  tall:         14 * 60_000,
  expert:       25 * 60_000,
};

export const DIFFICULTY_MULT: Record<EtchSize, number> = {
  sketch: 1, beginner: 2, intermediate: 4, tall: 5, expert: 8,
};

export interface SolveResult {
  solved: boolean;
  board: Board;
  lastTechnique: TechniqueLevel;
  iterations: number;
}

export interface GenerateRandomOpts {
  size: EtchSize;
  rng?: () => number;
  fillDensity?: number;
  maxAttempts?: number;
}

export interface GenerateResult {
  ok: boolean;
  solution?: ReadonlyArray<0 | 1>;
  classifiedAs?: EtchSize;
  attemptsTaken: number;
}

export interface ScoreOpts {
  size: EtchSize;
  actualMs: number;
  hintsUsed: number;
  mistakes: number;
  isDaily: boolean;
  streakDays: number;
}
