import { isHapticsEnabled, setHapticsEnabled, isSoundsEnabled, setSoundsEnabled } from './index';

let mounted = false;

export function mountFeedbackSettings() {
  if (mounted) return;
  mounted = true;

  // Watch for the theme popover to appear and inject haptics/sounds toggles
  const observer = new MutationObserver(() => {
    const slot = document.querySelector('[data-slot="theme-extras"]');
    if (slot && !slot.hasChildNodes()) {
      const div = document.createElement('section');
      div.innerHTML = `
        <h3 style="margin:0 0 6px;font-size:11px;opacity:0.6;text-transform:uppercase;letter-spacing:1px">Feedback</h3>
        <label style="display:flex;gap:8px;align-items:center;cursor:pointer;font-size:14px;padding:2px 0">
          <input type="checkbox" id="etch-haptics" ${isHapticsEnabled() ? 'checked' : ''}/>
          Haptics
        </label>
        <label style="display:flex;gap:8px;align-items:center;cursor:pointer;font-size:14px;padding:2px 0">
          <input type="checkbox" id="etch-sounds" ${isSoundsEnabled() ? 'checked' : ''}/>
          Sounds
        </label>
      `;
      slot.appendChild(div);
      const h = slot.querySelector('#etch-haptics') as HTMLInputElement | null;
      const s = slot.querySelector('#etch-sounds') as HTMLInputElement | null;
      h?.addEventListener('change', () => setHapticsEnabled(h.checked));
      s?.addEventListener('change', () => setSoundsEnabled(s.checked));
    }
  });

  observer.observe(document.body, { childList: true, subtree: true });
}
