import { solveBoard } from './solver';
import { makeBoard } from './board';
import type { EtchSize, TechniqueLevel } from './types';

const TECH_TO_SIZE: Record<TechniqueLevel, EtchSize> = {
  'none':                'sketch',
  'completed-clue':      'sketch',
  'forced-edge':         'beginner',
  'overlap':             'beginner',
  'completed-clue-elim': 'intermediate',
  'multi-line':          'expert',
};

export function classifyDifficulty(solution: ReadonlyArray<0|1>, w: number, h: number): EtchSize | null {
  const b = makeBoard(solution, w, h);
  const r = solveBoard(b);
  if (!r.solved) return null;
  const baseSize = TECH_TO_SIZE[r.lastTechnique];
  // Tall is a shape, not a technique tier. Promote intermediate to tall if h > w.
  if (baseSize === 'intermediate' && h > w) return 'tall';
  return baseSize;
}
