/**
 * Replay store — in-memory ring of board snapshots captured per move during the
 * current run. Persisted (compactly) to localStorage on solve so the win sheet
 * can offer a scrub/timelapse viewer.
 *
 * Storage cost: ~N * w*h bytes (1 byte per cell as a packed string) for a buffer
 * of N moves. We cap at 600 moves (covers any realistic 20x20 solve).
 *
 * Time complexity: snapshot is O(w*h); appending is amortized O(1) up to MAX.
 */
import type { Board } from '../engine';

const MAX_MOVES = 600;
const KEY = 'bilko_etch_replay_v1';

interface Frame { t: number; cells: string; }
interface Capture {
  rows: number; cols: number;
  solution: string;
  startedAt: number;
  frames: Frame[];
}

let live: Capture | null = null;

function pack(cells: ReadonlyArray<'unmarked' | 'fill' | 'cross'>): string {
  // 1 char per cell — '.' for unmarked, 'f' for fill, 'x' for cross.
  let s = '';
  for (let i = 0; i < cells.length; i++) {
    const c = cells[i];
    s += c === 'fill' ? 'f' : c === 'cross' ? 'x' : '.';
  }
  return s;
}

function packSolution(sol: ReadonlyArray<0 | 1>): string {
  let s = '';
  for (let i = 0; i < sol.length; i++) s += sol[i] === 1 ? '1' : '0';
  return s;
}

export interface ReplayFrame {
  t: number;
  /** Marks for every cell, in row-major order. */
  cells: ('unmarked' | 'fill' | 'cross')[];
}

export interface ReplayPayload {
  rows: number;
  cols: number;
  solution: (0 | 1)[];
  startedAt: number;
  frames: ReplayFrame[];
}

export function startReplayCapture(board: Board): void {
  live = {
    rows: board.rows, cols: board.cols,
    solution: packSolution(board.solution),
    startedAt: Date.now(),
    frames: [{ t: 0, cells: pack(board.cells) }],
  };
}

export function recordReplayBoard(board: Board): void {
  if (!live) return;
  // Hard cap — drop oldest non-zero frame if we exceed.
  if (live.frames.length >= MAX_MOVES) {
    live.frames.splice(1, 1); // keep frame 0 (empty board) for clean playback
  }
  live.frames.push({ t: Date.now() - live.startedAt, cells: pack(board.cells) });
}

/** Persist the current capture and clear the in-memory buffer. */
export function finishReplay(_final: Board): void {
  if (!live) return;
  try { localStorage.setItem(KEY, JSON.stringify(live)); } catch {}
  live = null;
}

function unpack(s: string): ('unmarked' | 'fill' | 'cross')[] {
  const out: ('unmarked' | 'fill' | 'cross')[] = new Array(s.length);
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    out[i] = ch === 'f' ? 'fill' : ch === 'x' ? 'cross' : 'unmarked';
  }
  return out;
}

export function getLastReplay(): ReplayPayload | null {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return null;
    const j = JSON.parse(raw) as Capture;
    return {
      rows: j.rows, cols: j.cols,
      solution: j.solution.split('').map(c => c === '1' ? 1 : 0) as (0 | 1)[],
      startedAt: j.startedAt,
      frames: j.frames.map(f => ({ t: f.t, cells: unpack(f.cells) })),
    };
  } catch { return null; }
}

export function clearLastReplay(): void {
  try { localStorage.removeItem(KEY); } catch {}
}
