/**
 * Customization preferences: accent color, cell border style, clue typography.
 *
 * Each setting writes a CSS variable / data-attribute on <html> so the rest of
 * the app can theme off it without React coupling. Persisted to localStorage.
 *
 * Time complexity: every helper is O(1).
 */

const ACCENT = 'bilko_etch_accent_v1';
const BORDER = 'bilko_etch_border_v1';
const CLUE_FACE = 'bilko_etch_cluefont_v1';

export type CellBorder = 'sharp' | 'rounded' | 'dotted';
export type ClueFace = 'numeric' | 'blocky' | 'etched';

export const ACCENT_PRESETS: ReadonlyArray<{ id: string; label: string; value: string }> = [
  { id: 'blue',   label: 'Blue',   value: '#3b82f6' },
  { id: 'plum',   label: 'Plum',   value: '#9333ea' },
  { id: 'forest', label: 'Forest', value: '#16a34a' },
  { id: 'sunset', label: 'Sunset', value: '#f97316' },
  { id: 'rose',   label: 'Rose',   value: '#e11d48' },
  { id: 'graphite', label: 'Graphite', value: '#475569' },
];

function isHex(v: string): boolean {
  return /^#?[0-9a-fA-F]{6}$/.test(v);
}

export function getAccent(): string {
  try {
    const raw = localStorage.getItem(ACCENT);
    if (raw && isHex(raw)) return raw.startsWith('#') ? raw : `#${raw}`;
  } catch {}
  return ACCENT_PRESETS[0]!.value;
}

export function setAccent(v: string): void {
  if (!isHex(v)) return;
  const normalized = v.startsWith('#') ? v : `#${v}`;
  try { localStorage.setItem(ACCENT, normalized); } catch {}
  applyAccent(normalized);
}

export function applyAccent(v: string): void {
  document.documentElement.style.setProperty('--etch-accent', v);
}

export function getCellBorder(): CellBorder {
  try {
    const v = localStorage.getItem(BORDER);
    if (v === 'rounded' || v === 'dotted') return v;
  } catch {}
  return 'sharp';
}

export function setCellBorder(b: CellBorder): void {
  try { localStorage.setItem(BORDER, b); } catch {}
  applyCellBorder(b);
}

export function applyCellBorder(b: CellBorder): void {
  document.documentElement.dataset['cellBorder'] = b;
}

export function getClueFace(): ClueFace {
  try {
    const v = localStorage.getItem(CLUE_FACE);
    if (v === 'blocky' || v === 'etched') return v;
  } catch {}
  return 'numeric';
}

export function setClueFace(f: ClueFace): void {
  try { localStorage.setItem(CLUE_FACE, f); } catch {}
  applyClueFace(f);
}

export function applyClueFace(f: ClueFace): void {
  document.documentElement.dataset['clueFace'] = f;
}

/** Boot-time: apply all persisted customizations to <html>. */
export function bootCustomize(): void {
  applyAccent(getAccent());
  applyCellBorder(getCellBorder());
  applyClueFace(getClueFace());
}
