import { useGameState, useGameActions } from '../state/store';
import { isForgivingWindow } from '../state/progression';

function fmt(ms: number): string {
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60), s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

/**
 * Jargon-free size labels for the HUD pill. "sketch" → "Tiny" etc. The
 * internal EtchSize enum keeps its values; only the visible label is
 * humanized. Time complexity: O(1) lookup.
 */
const SIZE_LABELS: Record<string, string> = {
  sketch: 'Tiny',
  beginner: 'Small',
  intermediate: 'Medium',
  tall: 'Tall',
  expert: 'Big',
};

export function HudSlot() {
  const s = useGameState();
  const a = useGameActions();
  const { board } = s;
  if (board.cells.length === 0) return null;
  // Hide the timer during the forgiving window (new players don't need time
  // pressure). The timer keeps ticking internally; we just don't display it.
  const inForgiving = isForgivingWindow();
  return (
    <div className="etch-hud" data-slot="hud">
      <span className="hud-pill">{SIZE_LABELS[s.size] ?? s.size}</span>
      {!inForgiving && (
        <span className="hud-timer" aria-live="off">{fmt(s.timeMs)}</span>
      )}
      {s.canUndo && (
        <button className="hud-btn" onClick={() => a.undo()} aria-label="Undo last move">↩</button>
      )}
      <button className="hud-btn" onClick={() => a.restart()} aria-label="Start over">↺</button>
      <button
        className="hud-btn"
        onClick={() => a.togglePrimary()}
        aria-label={s.primary === 'fill' ? 'Switch to crossing-out mode' : 'Switch to filling mode'}
        aria-pressed={s.primary === 'cross'}
      >
        {s.primary === 'fill' ? '■ Fill' : '× Cross'}
      </button>
      {s.mistakeLimit !== null && (
        <span className="hud-mistakes" aria-label={`${s.mistakes} mistakes`}>
          {s.mistakes}/{s.mistakeLimit}
        </span>
      )}
    </div>
  );
}
