export type ThemeChoice = 'light' | 'dark' | 'sepia' | 'system';

const KEY = 'bilko_etch_theme_v1';
const CB = 'bilko_etch_cb_v1';
const HC = 'bilko_etch_hc_v1';
const MIST = 'bilko_etch_mistake_v1';

function isThemeChoice(v: string | null): v is Exclude<ThemeChoice, 'system'> {
  return v === 'light' || v === 'dark' || v === 'sepia';
}

export function getTheme(): ThemeChoice {
  try {
    const v = localStorage.getItem(KEY);
    return isThemeChoice(v) ? v : 'system';
  } catch { return 'system'; }
}

export function setTheme(c: ThemeChoice) {
  if (c === 'system') {
    delete document.documentElement.dataset['theme'];
    try { localStorage.removeItem(KEY); } catch {}
  } else {
    document.documentElement.dataset['theme'] = c;
    try { localStorage.setItem(KEY, c); } catch {}
  }
}

export function getColorBlind(): boolean {
  try { return localStorage.getItem(CB) === '1'; } catch { return false; }
}

export function setColorBlind(on: boolean) {
  if (on) {
    document.documentElement.dataset['cb'] = '1';
    try { localStorage.setItem(CB, '1'); } catch {}
  } else {
    delete document.documentElement.dataset['cb'];
    try { localStorage.removeItem(CB); } catch {}
  }
}

export function getHighContrast(): boolean {
  try { return localStorage.getItem(HC) === '1'; } catch { return false; }
}

export function setHighContrast(on: boolean) {
  if (on) {
    document.documentElement.dataset['hc'] = '1';
    try { localStorage.setItem(HC, '1'); } catch {}
  } else {
    delete document.documentElement.dataset['hc'];
    try { localStorage.removeItem(HC); } catch {}
  }
}

export type MistakeMode = 'off' | '3' | '5';

export function getMistakeMode(): MistakeMode {
  try {
    const v = localStorage.getItem(MIST);
    if (v === '3') return '3';
    if (v === '5') return '5';
    return 'off';
  } catch { return 'off'; }
}

export function setMistakeMode(m: MistakeMode) {
  try {
    if (m === 'off') localStorage.removeItem(MIST);
    else localStorage.setItem(MIST, m);
  } catch {}
}

/**
 * Manual reduced-motion override. When true, suppress animations even when the
 * OS-level `prefers-reduced-motion` is `no-preference`. Applied via the
 * `data-reduced="1"` attribute on <html> — CSS reads it the same way it reads
 * the media query.
 */
const REDUCED = 'bilko_etch_reduced_v1';

export function getReducedMotion(): boolean {
  try { return localStorage.getItem(REDUCED) === '1'; } catch { return false; }
}

export function setReducedMotion(on: boolean) {
  if (on) {
    document.documentElement.dataset['reduced'] = '1';
    try { localStorage.setItem(REDUCED, '1'); } catch {}
  } else {
    delete document.documentElement.dataset['reduced'];
    try { localStorage.removeItem(REDUCED); } catch {}
  }
}

/** True if the user (via setting OR OS pref) wants reduced motion. */
export function prefersReducedMotion(): boolean {
  if (getReducedMotion()) return true;
  try { return matchMedia('(prefers-reduced-motion: reduce)').matches; } catch { return false; }
}
