const KEY = 'bilko_etch_haptics_v1';

function enabled(): boolean {
  try { return localStorage.getItem(KEY) !== '0'; } catch { return true; }
}

function vib(p: number | number[]) {
  if (!enabled()) return;
  try {
    if (typeof navigator?.vibrate === 'function') navigator.vibrate(p);
  } catch {}
}

export const haptics = {
  tap:     () => vib(10),
  tick:    () => vib(5),
  bump:    () => vib([20, 60, 20]),
  success: () => vib([15, 60, 15, 60, 30]),
  error:   () => vib([60, 30, 60, 30, 60]),
};

export function setHapticsEnabled(on: boolean) {
  try { localStorage.setItem(KEY, on ? '1' : '0'); } catch {}
}

export function isHapticsEnabled(): boolean { return enabled(); }
