import { useState, useEffect } from 'react';
import { useGameState, useGameActions } from '../../state/store';
import {
  getProgression, setProgression, shouldPromptHarder,
} from '../../state/progression';

/**
 * One-shot "want to try harder?" prompt. Shows after the 3rd win, between
 * the win sheet closing and the next puzzle starting. The player can:
 *   - say yes: opens difficulty picker (resets gameStartCount via abandon)
 *   - say no: persists declinedHarder=true, never auto-prompts again
 *   - dismiss: same as no
 *
 * Critically: this does NOT auto-upgrade the difficulty. We honor the brief:
 * "wait for opt-in".
 */
export function GraduationPrompt() {
  const s = useGameState();
  const a = useGameActions();
  const [show, setShow] = useState(false);

  // Re-check whenever winCount changes (puzzle gets solved)
  useEffect(() => {
    if (shouldPromptHarder() && !s.solved && s.board.cells.length > 0) {
      setShow(true);
      // Mark "prompted" so we never auto-show again, even if dismissed
      setProgression({ promptedHarder: true });
    }
  }, [s.solved, s.board.cells.length]);

  function yes() {
    setShow(false);
    // Drop the player into the picker (set gameStartCount back to 0 by
    // calling restart, which our store does).
    a.restart();
  }

  function no() {
    setProgression({ declinedHarder: true });
    setShow(false);
  }

  if (!show) return null;
  const winCount = getProgression().winCount;
  if (winCount < 3) return null;

  return (
    <div className="etch-graduation" role="status" data-testid="graduation-prompt">
      <p className="etch-graduation-text">
        Nicely done — you've solved {winCount} puzzles! Ready for something bigger?
      </p>
      <div className="etch-graduation-actions">
        <button
          type="button"
          className="etch-graduation-yes"
          onClick={yes}
          data-testid="graduation-yes"
        >
          Show me harder puzzles
        </button>
        <button
          type="button"
          className="etch-graduation-no"
          onClick={no}
          data-testid="graduation-no"
        >
          Not yet
        </button>
      </div>
    </div>
  );
}
