import { solveLine } from './line-solver';
import type { Board, Mark, TechniqueLevel } from './types';

export interface HintInfo {
  line: { kind: 'row' | 'col'; index: number };
  technique: TechniqueLevel;
  cell?: { row: number; col: number; kind: 'fill' | 'cross' };
}

/**
 * Find the next deducible move on the current board.
 *
 * Scans rows then columns; for each line, runs solveLine; reports the FIRST line
 * where a forced cell is currently 'unmarked' on the board. The cell returned is
 * the first forced cell in scan order from that line.
 *
 * Time: O((rows + cols) · solveLine) — bounded by PLACEMENT_CAP inside solveLine.
 */
export function nextHint(b: Board): HintInfo | null {
  // Rows first
  for (let r = 0; r < b.rows; r++) {
    const line = Array.from(b.cells.slice(r * b.cols, r * b.cols + b.cols)) as Mark[];
    const forced = solveLine(b.clues.rows[r]!, line);
    for (let i = 0; i < b.cols; i++) {
      if (forced[i] !== 'unmarked' && line[i] === 'unmarked') {
        return {
          line: { kind: 'row', index: r },
          technique: classifyLine(b.clues.rows[r]!, line, b.cols),
          cell: { row: r, col: i, kind: forced[i] === 'fill' ? 'fill' : 'cross' },
        };
      }
    }
  }
  // Columns
  for (let c = 0; c < b.cols; c++) {
    const line: Mark[] = [];
    for (let r = 0; r < b.rows; r++) line.push(b.cells[r * b.cols + c] as Mark);
    const forced = solveLine(b.clues.cols[c]!, line);
    for (let r = 0; r < b.rows; r++) {
      if (forced[r] !== 'unmarked' && line[r] === 'unmarked') {
        return {
          line: { kind: 'col', index: c },
          technique: classifyLine(b.clues.cols[c]!, line, b.rows),
          cell: { row: r, col: c, kind: forced[r] === 'fill' ? 'fill' : 'cross' },
        };
      }
    }
  }
  return null;
}

function classifyLine(clues: number[], line: ReadonlyArray<Mark>, N: number): TechniqueLevel {
  if (clues.length === 1 && clues[0] === 0) return 'completed-clue';
  const totalLen = clues.reduce((s, c) => s + c, 0) + (clues.length - 1);
  if (totalLen === N) return 'completed-clue';
  for (const c of clues) if (c * 2 > N) return 'overlap';
  // Check if line is mostly filled (completed-clue-elim)
  const filled = line.filter(c => c === 'fill').length;
  const clueSum = clues.reduce((s, c) => s + c, 0);
  if (filled >= clueSum) return 'completed-clue-elim';
  if (line[0] === 'fill' || line[N - 1] === 'fill') return 'forced-edge';
  return 'overlap';
}
