import { useEffect, type ReactNode } from 'react';
import { useStore } from '../state/store';

export function EngineSlot({ children }: { children: ReactNode }) {
  // Subscribe to gameStartCount so the interval restarts on each new game.
  // gameStartCount = 0 means no game has started; timer doesn't run.
  const gameStartCount = useStore(s => s.gameStartCount);

  useEffect(() => {
    if (gameStartCount === 0) return;
    const id = setInterval(() => {
      const s = useStore.getState();
      if (s.paused || s.solved || s.revealed) return;
      useStore.setState({ timeMs: s.timeMs + 1000 });
    }, 1000);
    return () => clearInterval(id);
  }, [gameStartCount]);

  useEffect(() => {
    function vis() {
      const hidden = document.visibilityState === 'hidden';
      useStore.getState().actions.pause(hidden);
    }
    document.addEventListener('visibilitychange', vis);
    return () => document.removeEventListener('visibilitychange', vis);
  }, []);

  // The scroller is the CSS grid container for col-clues / row-clues / board areas.
  // onMouseLeave is here so hover clears only when leaving the entire puzzle area,
  // not when the mouse moves between the clue bars and the board.
  return (
    <div
      className="etch-board-scroller"
      onMouseLeave={() => useStore.getState().actions.setHover(null)}
    >
      {children}
    </div>
  );
}
