import { verifyUniqueDeductive, verifyUnique } from './verifier';
import { computeClues } from './clues';
import { classifyDifficulty } from './classifier';
import { SIZE_DIMS } from './types';
import type { GenerateRandomOpts, GenerateResult } from './types';

export function generateRandom(opts: GenerateRandomOpts): GenerateResult {
  const { w, h } = SIZE_DIMS[opts.size];
  const rng = opts.rng ?? Math.random;
  const density = opts.fillDensity ?? 0.45;
  const maxAttempts = opts.maxAttempts ?? 200;

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    const sol: (0|1)[] = new Array(w * h);
    for (let i = 0; i < sol.length; i++) sol[i] = rng() < density ? 1 : 0;

    // Reject puzzles with empty rows/cols for small sizes
    if (opts.size === 'sketch' || opts.size === 'beginner') {
      const clues = computeClues(sol, w, h);
      if (clues.rows.some(r => r.length === 1 && r[0] === 0)) continue;
      if (clues.cols.some(c => c.length === 1 && c[0] === 0)) continue;
    }

    if (!verifyUniqueDeductive(sol, w, h)) continue;
    const clues = computeClues(sol, w, h);
    if (!verifyUnique(clues, w, h)) continue;

    const classified = classifyDifficulty(sol, w, h);
    if (classified === null) continue;
    if (classified !== opts.size) continue;

    return { ok: true, solution: sol, classifiedAs: classified, attemptsTaken: attempt + 1 };
  }
  return { ok: false, attemptsTaken: maxAttempts };
}
